SELECT count(*) FROM title, kind_type, cast_info, role_type, movie_keyword, char_name, name, movie_info, aka_name WHERE title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_keyword.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND movie_info.movie_id = title.id AND aka_name.person_id = name.id;